module RefModule(input Cen, initOne, clk, rst, output [7:0]Out);reg [7:0] p;
	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk, posedge rst or posedge dbg_halt) begin
		if(rst) p <= 8'b0;
		else
			if(initOne) p <= 8'd1;
			else if(Cen) p <= p+1;
			else p <= p;
	end
	assign Out = p;
endmodule
